//-----------------------------------------------------------------------------
// CreateToolbars                                               CATIShapeDesignWorkshopAddin
//-----------------------------------------------------------------------------
CATCmdContainer* MRFGSDAddin::CreateToolbars()
{

	NewAccess(CATCmdContainer, pMRFGSDSection, MRF);

	NewAccess(CATCmdContainer, pMRFGSDContainer, MRFGSDTlb);
	AddAccessChild(pMRFGSDSection, pMRFGSDContainer);

	NewAccess(CATCmdStarter, pStarterMRFGrooveSweep, MRFGrooveSweepbtn);
	SetAccessCommand(pStarterMRFGrooveSweep, "MRFGSDGrooveSweepCmdHdr");
	SetAccessChild(pMRFGSDContainer, pStarterMRFGrooveSweep);

	NewAccess(CATCmdStarter, pStarterPointVent, MRFPointVentbtn);
	SetAccessCommand(pStarterPointVent, "MRFPointVentCmdHdr");
	SetAccessNext(pStarterMRFGrooveSweep, pStarterPointVent);

	NewAccess(CATCmdStarter, pStarterSegmentPartition, MRFSegmentPartitionbtn);
	SetAccessCommand(pStarterSegmentPartition, "MRFSegmentPartitionCmdHdr");
	SetAccessNext(pStarterPointVent, pStarterSegmentPartition);

	NewAccess(CATCmdStarter, pVentAnalysis, MRFVentAnalysisbtn);
	SetAccessCommand(pVentAnalysis, "MRFVentAnalysisCmdHdr");
	SetAccessNext(pStarterSegmentPartition, pVentAnalysis);
	
	NewAccess(CATCmdStarter, pCircumVentAnalysis, MRFCircumVentRefinement);
	SetAccessCommand(pCircumVentAnalysis, "MRFCircumVentAnalysisCmdHdr");
	SetAccessNext(pVentAnalysis, pCircumVentAnalysis);

	NewAccess(CATCmdStarter, pStarterCircumVent, MRFCircumVentbtn);
	SetAccessCommand(pStarterCircumVent, "MRFCircumVentCmdHdr");
	SetAccessNext(pCircumVentAnalysis, pStarterCircumVent);

	NewAccess(CATCmdStarter, pStarterTWINSD, MRFTWINSDbtn);
	SetAccessCommand(pStarterTWINSD, "MRFTWIAndNSDCmdHdr");
	SetAccessNext(pStarterCircumVent, pStarterTWINSD);

	NewAccess(CATCmdStarter, pStarterShrinkeage, MRFSHKbtn);
	SetAccessCommand(pStarterShrinkeage, "MRFShrinkeageCmdHdr");
	SetAccessNext(pStarterTWINSD, pStarterShrinkeage);

	NewAccess(CATCmdStarter, pStarterDisassemble, MRFDisAssbtn);
	SetAccessCommand(pStarterDisassemble, "MRFDisAssembleHdr");
	SetAccessNext(pStarterShrinkeage, pStarterDisassemble);
	
	NewAccess(CATCmdStarter, pStarterTWIMarking, MRFTWIMarkingBtn);
	SetAccessCommand(pStarterTWIMarking, "MRFTWIMarkingCmdHdr");
	SetAccessNext(pStarterDisassemble, pStarterTWIMarking);

	NewAccess(CATCmdStarter, pStarterSipe, MRFSipebtn);
	SetAccessCommand(pStarterSipe, "MRFSipeAnalysisCmdHdr");
	SetAccessNext(pStarterTWIMarking, pStarterSipe);
	
	NewAccess(CATCmdStarter, pStarterSmoothCurve, MRFSmoothCrvbtn);
	SetAccessCommand(pStarterSmoothCurve, "MRFSmoothCurveHdr");
	SetAccessNext(pStarterSipe, pStarterSmoothCurve);

	NewAccess(CATCmdStarter, pStarterMountingHole, MRFMountingHoleBtn);
	SetAccessCommand(pStarterMountingHole, "MRFMountingAndLiftingHoleCmdHdr");
	SetAccessNext(pStarterSmoothCurve, pStarterMountingHole);

	NewAccess(CATCmdStarter, pStarterMRFTyreDepthAnsys, ButtonMRFTyreDepthAnsys);
	SetAccessCommand(pStarterMRFTyreDepthAnsys, "MRFTyreSurfDepthAnsysCmdHdr");
	SetAccessNext(pStarterMountingHole, pStarterMRFTyreDepthAnsys);
	
	//NewAccess(CATCmdStarter, pStarterProcessTool, MRFProcessToolBtn);
	//SetAccessCommand(pStarterProcessTool, "MRFProcessToolsCmdHdr");
	//SetAccessNext(pStarterMRFTyreDepthAnsys, pStarterProcessTool);
	
	NewAccess(CATCmdStarter, pStarterGenericProcessTool, MRFGenericProcessToolBtn);
	SetAccessCommand(pStarterGenericProcessTool, "MRFGenericProcessToolsCmdHdr");
	SetAccessNext(pStarterMRFTyreDepthAnsys, pStarterGenericProcessTool);

	NewAccess(CATCmdStarter, pStarterGreenProfile, MRFGreenProfileBtn);
	SetAccessCommand(pStarterGreenProfile, "MRFGreenProfileCmdHdr");
	SetAccessNext(pStarterGenericProcessTool, pStarterGreenProfile);

	NewAccess(CATCmdStarter, pStarterExportExcel, MRFExportExcelBtn);
	SetAccessCommand(pStarterExportExcel, "MRFExportExcelHdr");
	SetAccessNext(pStarterGreenProfile, pStarterExportExcel);

	return pMRFGSDSection; // return Section

}









